9	export async function uploadDocument(req: Request, res: Response, next: NextFunction) {
10	  try {
11	    if (!req.file) {
12	      res.status(400).json({ code: 400, msg: 'No file provided' });
13	      return;
14	    }
15	
16	    const dealershipId = req.user!.role === 'admin'
17	      ? req.scope?.dealershipId
18	      : (req.user!.dealershipId || req.scope?.dealershipId);
19	    if (!dealershipId) {
20	      res.status(400).json({ code: 400, msg: 'Dealership context required' });
21	      return;
22	    }
23	    const doc = await documentService.uploadDocument(req.file, {
24	      dealershipId,
25	      uploadedBy: req.user!.id,
26	      type: req.body.type || 'other',
27	      orderId: req.body.orderId,
28	      vehicleId: req.body.vehicleId,
29	      sensitiveFlag: req.body.sensitiveFlag === 'true',
30	    });
31	
32	    await logAuditEvent({
33	      dealershipId,
34	      userId: req.user!.id,
35	      role: req.user!.role,
36	      ip: req.ip || '',
37	      action: 'document.upload',
38	      resourceType: 'document',
39	      resourceId: doc._id?.toString() || '',
40	      after: { filename: doc.originalFilename, type: doc.type, sensitiveFlag: doc.sensitiveFlag, quarantined: doc.quarantined },
41	      requestId: (req as any).requestId,
42	    });
43	
44	    res.status(201).json(doc);
45	  } catch (error) {
46	    next(error);
47	  }
48	}
