3	const API_BASE = '/api/v1';
4	const HMAC_SECRET = import.meta.env.VITE_HMAC_SECRET;
5	if (!HMAC_SECRET) {
6	  throw new Error('VITE_HMAC_SECRET environment variable is required');
7	}
8	
9	// Routes that require HMAC signing
10	const HMAC_ROUTE_PREFIXES = ['/cart', '/orders', '/documents', '/finance', '/admin', '/privacy', '/audit'];
11	
12	function needsHmac(url: string): boolean {
13	  const path = url.startsWith(API_BASE) ? url.slice(API_BASE.length) : url;
14	  return HMAC_ROUTE_PREFIXES.some((prefix) => path.startsWith(prefix));
15	}
16	
17	async function generateHmac(
18	  method: string,
19	  path: string,
20	  body: string,
21	  timestamp: string,
22	  secret: string
23	): Promise<string> {
24	  const encoder = new TextEncoder();
25	  const key = await crypto.subtle.importKey(
26	    'raw',
27	    encoder.encode(secret),
28	    { name: 'HMAC', hash: 'SHA-256' },
29	    false,
30	    ['sign']
31	  );
32	  const payload = `${method.toUpperCase()}\n${path}\n${body}\n${timestamp}`;
33	  const signature = await crypto.subtle.sign('HMAC', key, encoder.encode(payload));
34	  return Array.from(new Uint8Array(signature))
35	    .map((b) => b.toString(16).padStart(2, '0'))
36	    .join('');
37	}
38	
39	const httpClient = axios.create({
40	  baseURL: API_BASE,
41	  headers: { 'Content-Type': 'application/json' },
42	});
43	
44	httpClient.interceptors.request.use(async (config) => {
45	  const token = localStorage.getItem('accessToken');
46	  if (token) {
47	    config.headers.Authorization = `Bearer ${token}`;
48	  }
49	
50	  const timestamp = new Date().toISOString();
51	  config.headers['X-Timestamp'] = timestamp;
52	
53	  const fullUrl = config.baseURL
54	    ? `${config.baseURL}${config.url || ''}`
55	    : config.url || '';
56	
57	  if (needsHmac(fullUrl)) {
58	    const method = (config.method || 'GET').toUpperCase();
59	    // Build the path as the server sees it (includes query string)
60	    let path = fullUrl;
61	    if (config.params) {
62	      const qs = new URLSearchParams(config.params).toString();
63	      if (qs) path = `${path}?${qs}`;
64	    }
65	    // For multipart/form-data (file uploads), sign with empty body since the server
66	    // cannot reconstruct the multipart body for verification
67	    const isMultipart = config.data instanceof FormData;
68	    const body = isMultipart ? '' : (config.data ? (typeof config.data === 'string' ? config.data : JSON.stringify(config.data)) : '');
69	    config.headers['X-Hmac-Signature'] = await generateHmac(method, path, body, timestamp, HMAC_SECRET);
70	  }
71	
72	  return config;
73	});
74	
75	httpClient.interceptors.response.use(
76	  (response) => response,
77	  async (error) => {
78	    if (error.response?.status === 401) {
79	      const refreshToken = localStorage.getItem('refreshToken');
80	      if (refreshToken && !error.config._retry) {
81	        error.config._retry = true;
82	        try {
83	          const { data } = await axios.post(`${API_BASE}/auth/refresh`, { refreshToken });
84	          localStorage.setItem('accessToken', data.accessToken);
85	          localStorage.setItem('refreshToken', data.refreshToken);
86	          error.config.headers.Authorization = `Bearer ${data.accessToken}`;
87	          return httpClient(error.config);
88	        } catch {
89	          localStorage.removeItem('accessToken');
90	          localStorage.removeItem('refreshToken');
91	          window.location.href = '/login';
92	        }
93	      }
94	    }
95	    return Promise.reject(error);
96	  }
97	);
98	
99	export default httpClient;
