24	export async function addToCart(
25	  userId: string,
26	  dealershipId: string,
27	  vehicleId: string,
28	  addOnServices: Array<{ serviceCode: string }> = []
29	) {
30	  const vehicle = await Vehicle.findById(vehicleId);
31	  if (!vehicle) throw new NotFoundError('Vehicle not found');
32	  if (vehicle.dealershipId?.toString() !== dealershipId) {
33	    throw new BadRequestError('Vehicle does not belong to the current dealership');
34	  }
35	  if (vehicle.status !== VehicleStatus.AVAILABLE) {
36	    throw new BadRequestError('Vehicle is not available');
37	  }
38	
39	  let cart = await Cart.findOne({ userId, dealershipId });
40	  if (!cart) {
41	    cart = new Cart({ userId, dealershipId, items: [] });
42	  }
43	
44	  const alreadyInCart = cart.items.some(
45	    (item) => item.vehicleId.toString() === vehicleId
46	  );
47	  if (alreadyInCart) {
48	    throw new BadRequestError('Vehicle already in cart');
49	  }
50	
51	  const addOns = addOnServices
52	    .map((a) => AVAILABLE_ADDONS.find((ao) => ao.serviceCode === a.serviceCode))
53	    .filter(Boolean) as typeof AVAILABLE_ADDONS;
54	
55	  cart.items.push({
56	    vehicleId: vehicle._id as any,
57	    addOnServices: addOns,
58	    addedAt: new Date(),
59	  });
60	
61	  await cart.save();
62	  return Cart.findById(cart._id).populate('items.vehicleId');
63	}
