71	  if (!cart) throw new NotFoundError('Cart not found');
72	
73	  cart.items = cart.items.filter(
74	    (item) => item.vehicleId.toString() !== vehicleId
75	  );
76	
77	  await cart.save();
78	  return Cart.findById(cart._id).populate('items.vehicleId');
79	}
