1	import { User } from '../../models/user.model';
2	import { Order } from '../../models/order.model';
3	import { Payment } from '../../models/payment.model';
4	import { Invoice } from '../../models/invoice.model';
5	import { WalletTransaction } from '../../models/wallet-transaction.model';
6	import { NotFoundError } from '../../lib/errors';
7	import logger from '../../lib/logger';
8	
9	const USER_PURGE_DAYS = 30;
10	const FINANCIAL_RETENTION_DAYS = 2555; // ~7 years for regulatory compliance
11	
12	export async function requestAccountDeletion(userId: string) {
13	  const user = await User.findById(userId);
14	  if (!user) throw new NotFoundError('User not found');
15	
16	  user.isActive = false;
17	  user.deletedAt = new Date();
18	  user.pendingPurge = true;
19	  user.profile.firstName = '[REDACTED]';
20	  user.profile.lastName = '[REDACTED]';
21	  user.profile.phone = '';
22	  user.profile.driversLicense = '';
23	  user.profile.driversLicenseEncrypted = null as any;
24	  user.profile.ssn = '';
25	  user.profile.ssnEncrypted = null as any;
26	
27	  await user.save();
28	
29	  logger.info({ userId }, 'Account deletion requested - PII removed, 30-day retention hold');
30	
31	  return {
32	    status: 'deletion_requested',
33	    retentionUntil: new Date(Date.now() + USER_PURGE_DAYS * 24 * 60 * 60 * 1000),
34	    financialRecordsRetainedUntil: new Date(Date.now() + FINANCIAL_RETENTION_DAYS * 24 * 60 * 60 * 1000),
35	  };
36	}
37	
38	export async function purgeExpiredAccounts() {
39	  const thirtyDaysAgo = new Date(Date.now() - USER_PURGE_DAYS * 24 * 60 * 60 * 1000);
40	
41	  const usersToPurge = await User.find({
42	    pendingPurge: true,
43	    deletedAt: { $lte: thirtyDaysAgo },
44	  });
45	
46	  let purgedCount = 0;
47	
48	  for (const user of usersToPurge) {
49	    const hasActiveFinancialRecords = await hasRetainedFinancialRecords(user._id.toString());
50	
51	    if (hasActiveFinancialRecords) {
52	      // Anonymize the user record but preserve financial references
53	      await anonymizeForFinancialRetention(user._id.toString());
54	      logger.info(
55	        { userId: user._id },
56	        'User anonymized but retained for financial record compliance'
57	      );
58	    } else {
59	      await User.findByIdAndDelete(user._id);
60	      purgedCount++;
61	    }
62	  }
63	
64	  if (purgedCount > 0) {
65	    logger.info({ count: purgedCount }, 'Expired accounts purged');
66	  }
67	
68	  return purgedCount;
69	}
