const http = require('http');
const crypto = require('crypto');
const BASE_URL = 'http://localhost:5000';

function generateHmac(method, path, body, timestamp, secret) {
  const payload = method + '\n' + path + '\n' + body + '\n' + timestamp;
  return crypto.createHmac('sha256', secret).update(payload).digest('hex');
}

async function req(method, path, body, token, signingKey) {
  return new Promise((resolve, reject) => {
    const url = new URL(path, BASE_URL);
    const fullPath = url.pathname + url.search;
    const timestamp = new Date().toISOString();
    const bodyStr = body ? JSON.stringify(body) : '';
    const options = {
      hostname: url.hostname, port: url.port, path: fullPath, method,
      headers: { 'Content-Type': 'application/json', 'X-Timestamp': timestamp },
    };
    if (signingKey) {
      options.headers['X-Hmac-Signature'] = generateHmac(method, fullPath, bodyStr, timestamp, signingKey);
    }
    if (token) options.headers['Authorization'] = 'Bearer ' + token;
    const r = http.request(options, (res) => {
      let data = '';
      res.on('data', (c) => data += c);
      res.on('end', () => { try { resolve({status: res.statusCode, data: JSON.parse(data)}); } catch { resolve({status: res.statusCode, data}); } });
    });
    r.on('error', reject);
    if (body) r.write(JSON.stringify(body));
    r.end();
  });
}

(async () => {
  // Login buyer
  const login = await req('POST', '/api/v1/auth/login', {email: process.env.BUYER_EMAIL, password: process.env.BUYER_PASSWORD});
  console.log('Login status:', login.status);
  const buyerToken = login.data.accessToken;
  const signingKey = login.data.signingKey;
  console.log('Has signing key:', !!signingKey);
  console.log('Buyer dealershipId from JWT:', JSON.parse(Buffer.from(buyerToken.split('.')[1], 'base64').toString()).dealershipId);

  // Get vehicles
  const vehicles = await req('GET', '/api/v1/vehicles');
  const v = vehicles.data.data[0];
  console.log('Vehicle:', v._id, 'dealershipId:', v.dealershipId);

  // Try add to cart
  const cartRes = await req('POST', '/api/v1/cart/items', {vehicleId: v._id, addOnServices: [{serviceCode: 'inspection'}]}, buyerToken, signingKey);
  console.log('Cart add status:', cartRes.status);
  console.log('Cart add response:', JSON.stringify(cartRes.data));
})();
