const http = require('http');
const crypto = require('crypto');

function generateHmac(method, path, body, timestamp, secret) {
  return crypto.createHmac('sha256', secret).update(method+'\n'+path+'\n'+body+'\n'+timestamp).digest('hex');
}

function req(method, path, body, token, signingKey) {
  return new Promise((resolve, reject) => {
    const url = new URL(path, 'http://localhost:5000');
    const fullPath = url.pathname + url.search;
    const timestamp = new Date().toISOString();
    const bodyStr = body ? JSON.stringify(body) : '';
    const options = { hostname: url.hostname, port: url.port, path: fullPath, method, headers: { 'Content-Type': 'application/json', 'X-Timestamp': timestamp } };
    if (signingKey) options.headers['X-Hmac-Signature'] = generateHmac(method, fullPath, bodyStr, timestamp, signingKey);
